@font-face {
  font-family: Inter;
  src: url(https://tinybase.org/fonts/inter.woff2) format("woff2");
}

* {
  box-sizing: border-box;
}

body {
  font-family: Inter, sans-serif;
  margin: 0;
}

main {
  display: grid;
  gap: 1rem;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  margin: 2rem auto;
  max-width: 72rem;
  padding: 0 2rem;

  section {
    min-width: 0;
  }
}

.chart {
  display: block;
  font-size: 12px;
  height: 14rem;
  width: 100%;

  .grid {
    color: #d8e1eb;
    stroke-dasharray: 4 6;
  }

  .axes {
    color: #677489;

    .title {
      fill: #1f2937;
      font-weight: 700;
    }
  }

  .area {
    fill-opacity: 0.1;
  }

  .line {
    fill: none;
    stroke-linecap: round;
    stroke-linejoin: round;
    stroke-width: 3;
  }

  .points {
    fill: white;
    stroke-width: 2;
  }
}

.series-revenue {
  .area {
    fill: #2b8c67;
  }

  .line,
  .points {
    stroke: #2b8c67;
  }
}

.series-profit {
  .area {
    fill: #d16b3f;
  }

  .line,
  .points {
    stroke: #d16b3f;
  }

  .bar {
    fill: #d16b3f;
  }
}

.series-orders {
  .bar {
    fill: #5367c9;
  }
}

.chart-mixed {
  .series-revenue {
    .area {
      fill: none;
    }

    .line {
      stroke-width: 4;
    }
  }
}

@media (max-width: 52rem) {
  main {
    grid-template-columns: 1fr;
  }
}

